return {
	PetrifiedStatue = { "This stone carving is warm to the touch, that doesn\'t seem right...", "I can\'t shake the feeling of realness from these carvings.", "Something isn\'t right about this statue.", "This statue is posed in an almost uncomfortable manner. I wonder who created it.", "These statues are comprised of fresh stone, and the texture of the subjects is almost too real.", "The statue has a sad look about it. Is that-- a petrified tear? Oh no. Silly me, just some morning dew.", "This is a statue. Wait, this is just a statue, right? Looking closer, it seems like a statue. But it feels like something more." },
	Offerings = { "This looks like some kind of offering; yummy horse treats and flowers are placed around.", "I wonder what significance this foal had. There is a human statue embracing it.", "I can almost feel the melancholy emotions thick in the air... Maybe I should bring a gift next time I\'m here." },
	StatueOffering = { "These statues appear to be raising their hands either in offering, or in a receiving manner.", "The statues are crafted with a strong stone base, no visible cracks or weathering is apparent." },
	Blessing = { "This statue looks like some kind of magical gift is being bestowed upon people.", "Even from here, I can sense magic from the statues. I wonder what these mean?", "I wonder what entity provided these magical gifts.", "The magic radiates with power and various emotions.", "This statue is rich to the touch with excited and bright magic; it\'s buzzing against my hand!" },
	RoyalGuild = { "You flip to a random page and read. The royal kings guild is a high class of talented individuals sworn to defend Aetheron. Various ranks identify the class of problem the individual may encounter. Rankings go from sentinel, guardian, protector, warden, defender, and finally a kingsman.", "You flip to a random page and read. Those within guilds take upon various quests as simple as helping with chores around Aetheron, assisting the weak or less fortunate, or protecting Aetheron from nightmarish curiosities.", "You flip to a random page and read. To be accepted into a guild an individual must have a high amount of skill or magic capabilities. Maintaining guild status requires active guild activities. All ranges of humans, hybrids, and horses are encouraged to participate in guilds.", "You flip to a random page and read. A unique bond exists between members of the Royal Guild. Guild oaths are more than words\226\128\148they bind members\226\128\153 spirits, granting them strength when defending one another in times of crisis. The closer the bond, the stronger their shared power.", "You flip to a worn and torn page. It is said that not all guilds remain known to the world. Some ancient guilds vanished in mysterious circumstances, leaving behind clues hidden in the depths of forgotten ruins. Aetherons guild has existed for thousands of years, much of this old knowledge lost.", "You flip to a random page and read. The title of Kingsman is as much a burden as it is an honor. With it comes not only the protection of Aetheron but also the task of deciding the fate of entire realms. Kingsmen hold the power to reshape the very fabric of the world\226\128\148but wielding such power always comes at a cost. Very few have achieved this rank.", "You flip to a random page and read. Long before the guilds became powerful defenders of Aetheron, they were humble organizations born from the needs of the people. In the earliest days, guilds were formed to help one another, acting as couriers, transporting vital goods across the land, aiding with agricultural labors during harvest seasons, and even hunting to help feed the needy." },
	SpiritHorse = { "The page reads: Aqualis, the shimmering blue spirit horse of water, protects all aquatic sources and the creatures within. Known for its kindness, Aqualis is also cautious of newcomers. This spirit horse favors sweet, sugary offerings and is greatly pleased by those who play, swim, and bathe in its waters.", "The page reads: Terravine, the spirit horse of life, is a recognizable green being that roams the land, invigorating the life beneath its hooves. Terravine favors baked goods seasoned with warm spices like nutmeg and cinnamon. Planting trees, watering plants, and caring for nature greatly please this spirit.", "The page reads: Ashara, the spirit horse of fire, burns with a fierce energy. Ashara is both a protector and a destroyer, making way for new life by cleansing the old with its flames. This spirit horse favors offerings of roasted nuts and spiced meats. Those who kindle fires to warm the cold or burn away the deadwood of life earn Ashara\226\128\153s favor.", "The page reads: Aetheris, the spirit horse of history and time, commands the flow of ages with the strength of a warrior. Aetheris is a protector of knowledge, a guardian of ancient secrets, and a master of destiny. He favors offerings of aged wine, ancient relics, or artifacts with deep history. Sharing historical stories and adventures with other is the primary way to earn Aetheris\226\128\153 powerful favor." },
	Orion = { "This statue is incredibly old; deep, aged cracks and divots are clearly visible.", "This statue is of a centaur reaching up for a gift of some sort.", "The magic emanating from this statue feels off; it\'s unwelcoming and cold.", "There seems to be burnt ground surrounding the statue; warm embers burn without end.", "To the touch, this statue feels cold with dread; a dark magic pulses within." },
	Centaur = { "This statue is incredibly old; deep, aged cracks and divots are clear, as well as thick ancient moss.", "This appears to be a centaur, a horse-bodied being with the upper torso of a human.", "This fallen statue seems to be strewn about; this resting place must be unintentional.", "There is no magic emanating from these statues whatsoever; to the touch, they feel completely empty." },
	Magicwater = { "Mystical energies are dancing around this fountain; the air feels so light!", "The water in the fountain is surrounded by statues. I wonder what purpose it\'s used for!", "I wonder what would happen if I touched the water; it looks crystal clear and shimmers with magic." },
	PortalBroken = { "This large stone structure is inscribed with faded runes. It seems like it would have been a portal.", "A weakened magic is emanating from this stone structure. Is it missing another piece?" },
	Portal = { "This must be a portal. The runes glow dimly, and I can sense a faint magic within.", "I wonder why this portal is not working. It looks to be fully intact.", "A horse and human seem to have been inches away from this portal. This seems like an odd placement for statues." },
	Aqueduct = { "This structure is a magical aqueduct. I can hear water surging from deep within the planet straight to the top.", "This aqueduct is so large, it could have easily supplied water for millions.", "There are signs of massive demolition; something big must have happened to cause such ruin.", "Despite enduring significant destruction, the magic within the structure still beckons water upwards, even if it causes spillage." },
	MotherNature = { "This statue is surrounded by a shimmering green aura, carrying a sense of safety within.", "Upon the human\'s head is glowing reed-like moss, shimmering as if it were alive.", "The horse statue paired with the human is gently extending its wings, as if protecting the green-haired human.", "I feel a welcoming energy of peace and calm in this area. I think I could stay here forever." },
	Unknown = { "These statues appear to be kneeling humbly before the ocean.", "The largest statue displayed adorns wings, I wonder why." },
	PlushMachine = { "This machine appears to be advanced technology, though it\226\128\153s heavily deteriorated and overgrown with plants.", "Faint remnants of magic seem to keep it running... I wonder what its source might be.", "Signs of wear on different parts suggest it was once used regularly.", "Some of the internal gears look newer than others, as if someone tried to repair it recently.", "A faint humming noise can be heard when you\226\128\153re close, almost like a heartbeat.", "Protected within a funnel capsule is a pink lit heartstone of sorts, it appears to be fading." },
	SpiritHorseOrigins = { "Table of Contents: An in-depth research study on how spirit horses came to be. Despite the lack of historical knowledge, there is much to discover about these spirit entities that live among us.", "Illustration: This page features a spirit horse. The origins of spirit horses remain largely unknown, but hints suggest that magic may stem from objects, emotions, and other sources." },
	HistoryOfMagic = { "Table of Contents: A comprehensive history of magic, from its birth and creation to its study by humans and horses today, exploring how it is used in all aspects of life.", "Illustration: A depiction of the magic chakra flowing through both horses and humans. This simple rendering shows how magic travels through veins and nerves, with unique patterns for each species." },
	AetheronsPortals = { "Table of Contents: This study walks through the history of Aetheron\'s portal system, the creation of portals, and briefly touches on the dark portals from which horrors emerge.", "Illustration: This watercolor piece features a stone portal structure with vibrant magic swirling at its center. Wooden boards nailed to the stone indicate the portal\'s destination." },
	MonstersAndBeasts = { "Table of Contents: A documentation of encounters with various monsters, beasts, and entities that emerge from the dark portals scattered throughout Aetheron, exploring the magic behind these dark portals.", "Illustration: Bloodbane. A rough charcoal sketch depicts a terrifying beast with torn, outstretched wings, a draconic face, and massive protruding fangs. Its thick tail bristles with blade-like spines. DO NOT ENGAGE." },
	BrokenUnicornHorn = { "Looks like some kind of broken horn.", "It\'s swirling with vibrant colors and the interior is magic infused.", "For some reason it\'s impaling this structure." },
	Ghoulsteed = { "If your ghoulsteed ever becomes agitated, it\'s known that singing lullabyes to your ghoul can calm them.", "Ghoulsteeds are undead equines, emerging from the earth after years of time, any species of horse can become a ghoulsteed!", "Ghoulsteeds are some of the strongest species in the land, despite their aged bones and decaying bodies, the magic that fuels them holds enormous energy.", "Ghoulsteeds despites their appearance are very kind and playful horses with big personalities! They love rolling in the grass and sleeping flat on the ground.", "Ghoulsteeds once reborn as an undead, can live on for hundreds of thousands of years without tiring out and returning back to the earth.", "Ghoulsteeds can clearly see spirits and entities humans and other horses may not easily see.", "Ghoulsteeds love to be pampered! Spend a day cleaning your ghouls ribcage, coat, and teeth! Keeping a moisturized ghoul is vital to their happiness.", "Mischievous and playful spirits resurrect ghouls when they dance and spread magic on top of a horse\'s burial place! The magic mixing with the horse\'s soul is incredibly powerful, awakening the horse." },
	FrozenBones = { "These bones are frozen in perma ice, a deep dark blue shimmer radiates on the surface.", "The bones are something of nightmares, jagged teeth and fangs, and oversized ribcages... freaky!", "Occasionally, ghostly blue flames flicker above the Frozen Bones during the longest nights of winter.", "The winds that howl through the icy caverns where the Frozen Bones rest carry eerie melodies.", "Some say the bones are merely a warning. Buried deep below the frozen wasteland, the rest of the demons lie dormant, their bodies fused with the ice.", "Within the bone marrow, a faint and lethargic dark magic lingers. At my touch, it stirs, becoming agitated." },
	FrozenHorse = { "Encased in radiant ice that gleams like crystal, these horses are frozen mid-battle, their poses fierce and resolute.", "The holy ice glows faintly, as if a flame is frozen within. Some say the horses\' spirits still burn bright, their divine energy preventing the demons\' magic from spreading further.", "The ice captures not just their bodies but their final moments\226\128\148the clash of light and darkness frozen in time.", "The ice feels cool, not cold, radiating a warm energy of hope. A gentle shimmer glows within these frozen statues, as if the ice cradles them in its frigid yet tender embrace." },
	AlcesHero = { "Alpine\'s journey began with humble origins. Born as a runty Alces, he was often overlooked and underestimated by others.Frail in build and lacking both strength and magical prowess, Alpine\'s circumstances seemed bleak. Yet, despite these hardships, he was driven by a deep desire to help those around him, no matter his limitations.", "Determined to overcome his weaknesses, Alpine joined the Alces training clans, seeking a path to self-improvement. Though his physical abilities fell short, he displayed an unwavering dedication to learning. Alpine absorbed knowledge from those around him, tirelessly striving to grow, even when he struggled to put his lessons into practice.", "One fateful day, the land was consumed by an unrelenting storm. The skies churned with blinding blizzards, and the snow fell so heavily that one could barely see their own hooves. It was in this moment of chaos that something extraordinary and unprecedented happened to Alpine.", "Within the heart of the storm, a hidden strength within him was unleashed\226\128\148one that had been dormant, trapped by the very forces of nature. Alpine transformed into a magnificent elder Alces, his pelt shimmering white with permafrosted ice. The storm, which had once raged uncontrollably, now bent to his will, obeying his every command.", "Guided by this newfound power, Alpine braved the storm and found his lost and injured clanmates. With the blizzard under his control, he led them safely back to shelter, proving that even the smallest beginnings can lead to greatness.", "Alpine\'s journey began with humble origins. Born as a runty Alces, he was often overlooked and underestimated by others." },
	Alpine = { "Alpine was a selfless Alces who always thought of others before himself, his memorial stands as a symbol to all horses and Alces.", "Alpine\'s memorial displays baby horses on his back and his clan following behind him, a showcase of his efforts to lead and carry his clan to safety.", "In the moment the storm began, Alpine became his true elder form where normall it would take hundreds of years, Alpine had truly been blessed by the blizzard." },
	AlcesLore = { "The Alces are renowned for their diverse abilities, most notably their mastery of ice magic, immense strength, and extraordinary healing powers. These traits have made them legendary figures in the histories of Aetheron.", "The Alces\' healing powers are deeply rooted in their history and survival in the unforgiving tundras. When humans or horses became lost in the frigid lands, the Alces developed techniques to heal injuries caused by avalanches, frostbite, and illnesses brought on by the relentless cold. Over centuries, their healing skills evolved, blending physical remedies with innate magical energy, enabling them to mend both bodies and spirits.", "The Alces\' strength lies in their imposing size and the raw power of their antlers. This physical prowess made them formidable defenders of Aetheron during times of strife. When demons emerged to threaten the land, the Alces took to the battlefields as both warriors and healers. Their thunderous charges scattered foes, while their resilience inspired hope among allies.", "The Alces\' mastery of ice and snow magic is a gift bestowed by the spirits who revere them deeply. It is said that the Snow Spirit often plays with young Alces, gently blanketing them in flurries to foster their affinity with the cold. Meanwhile, the Ice Spirit watches over Alces as they train, sharpening their abilities and preparing them for the trials of battle.", "Alces lifespan is hundreds of years, the eldest alces can even grow past thousands. As Alces age, their blood begins to cool until it freezes completely. The Alces becomes white, entire body frosting over with shimmering white ice." },
	SantaVillage = { "Alces and elves work together to sort packages, preparing them for delivery. The elve\'s nimble hands quickly wrap and label gifts, while the Alces, with their immense strength, load the heavy gifts into a sled.", "Winged Alces were renowned as the elven village\'s top traders, relied upon to transport goods to and from the gingerbread village. They also delivered finished products and presents across all of Aetheron!", "Santa in the gingerbread village is actually a towering elf with a unique talent for crafting joyful toys and delectable treats, which he eagerly shares throughout the world of Aetheron.", "This building is full of activity as the Alces help the elves. Their teamwork helps keep Santa\'s village running smoothly." },
	Valentines1 = { "Pastrequines are not born in the wild but are delicately crafted by the finest artisans of the land, each infused with a special magic that brings their sweet essence to life.", "Every Pastrequine carries the spirit of its creator, reflecting the love and care poured into its doughy heart. No two are ever exactly the same!", "While their frosting glistens and their bodies smell of warm pastries, Pastrequines are far too magical to be eaten\226\128\166 though many a foal has tried to sneak a nibble!", "Some Pastrequines only appear during special times of the year, reflecting the flavors and colors of festive treats\226\128\148gingerbread for winter, strawberry shortcake for spring, and pumpkin spice for autumn!", "Those who bond with a Pastrequine often find themselves drawn to baking, as if the magic of their companion inspires their own culinary creativity.", " Each Pastrequine has a unique scent, ranging from warm cinnamon rolls to fresh fruit tarts. Some believe the aroma reflects their temperament, with the warmest hearts smelling of vanilla and caramel." },
	Valentines2 = { "Once upon a time, before the land was rich with sugar and magic, this realm was a simple, unassuming valley. It was said that a legendary p\195\162tissier, known only as the Crimson Confectioner, arrived in this barren place with a dream\226\128\148to create a paradise where love, sweetness, and artistry could flourish.", "\'Let love take root.\' As the Crimson Confectioner spun threads of sugar into the air, the winds carried them across the land, settling into the soil and taking shape as vibrant red and pink heart-shaped trees.", "To the north, the Magical Garden of Roses flourished under the care of devoted sugar sprites. Here, an endless array of flowers bloom, each more vibrant than the last, their petals infused with the essence of sugar, honey, and the lingering scent of romance.", "At the heart of the land stands the Crimson Confectioner\226\128\153s Castle, a grand palace surrounded by trees with red, black, and white heart-shaped leaves.", "To the east lies the Chocolate Frosting Canyon, a breathtaking marvel sculpted from the finest white, milk, and dark chocolates, forever rich and never melting. The canyon formed when the Crimson Confectioner poured a river of molten cocoa across the land, cooling it with a gentle spell of preservation.", "Long after the land was shaped into its current form, it remained empty of life. The Confectioner, realizing that something was missing, ventured into their castle and retrieved a sacred cookbook." },
	Valentines3 = { "Before the Sweetheart Kingdom flourished, before the first Pastrequine pranced across candy-lined paths, the land was nothing but a desolate, cracked wasteland.", "Legends speak of a time when the land was known only as The Hollow Expanse, a forsaken realm where nothing could grow, and nothing dared to thrive. The earth was ashen and crumbled at the slightest touch, water had long since dried into dust, and the air carried the scent of despair.", "It was a realm of hopelessness, a void where dreams perished before they could be born. Until one day\226\128\166 a dream did take root.", "From lands unknown, a lone figure arrived, clad in a cloak of crimson and carrying nothing but a simple satchel of ingredients and an old, tattered whisk. They were known only as The Crimson Confectioner, a name whispered like an old fairy tale, though no one truly knew where they had come from.", "Standing in the heart of the Hollow Expanse, the Confectioner saw not a dead land, but a blank canvas\226\128\148a place that could be shaped, molded, and given life once more. With hands steady and heart full, they knelt upon the dry, fractured earth and traced a single line in the dust. A recipe, the first of many." },
	Valentines4 = { "Nestled within the Sweetheart Kingdom, scattered across the Cotton Candy Heart Forest and beyond, are the Cake Villages, where both human and Pastrequine inhabitants live in harmony.", "It is said that when an inhabitant settles in the Sweetheart Kingdom, their home bakes itself into existence, rising from the ground like a freshly made cake, adorned with frosting, fillings, and decorations unique to its resident\226\128\153s spirit.", "Unlike ordinary homes, each dwelling is a delicious, magical creation, infused with the very essence of its owner\226\128\153s soul.", "No two houses are ever alike, for they take on the flavors, textures, and decorations that best reflect the hearts of those who live inside." },
	Valentines5 = { "At the very core of the Sweetheart Kingdom, nestled between the Cotton Candy Heart Forest and the Chocolate Frosting Canyon, lies the central city of Confectioner\226\128\153s Haven", "This city is the heart of the land\226\128\153s economy, a place where every scent in the air tells a story, and every corner holds a taste of something wonderful.", "Unlike the cake villages that rise from an individual\226\128\153s soul, Confectioner\226\128\153s Haven was shaped by the will of the people, built over generations by those who sought a place where creativity and sustenance could intertwine.", "While the city is lively, its people are deeply connected to the land that sustains them. Many of Confectioner\226\128\153s Haven\226\128\153s inhabitants travel to different regions daily, returning in the evening to share their goods and experiences.", "The legacy of the Crimson Confectioner is woven into every street, every shop, and every oven in the city. To the people, the Confectioner was more than just a baker\226\128\148they were a visionary, an artist, and a dreamer who shaped the very foundation of their world.", "Confectioner\226\128\153s Haven is not just a city\226\128\148it is a living, breathing testament to the magic of creation. It thrives not through power, nor through wealth, but through passion, artistry, and the shared belief that the world is always sweeter when built with love." },
	CrimsonCastle = {
		"At the heart of the Sweetheart Kingdom, where once the greatest dreamer shaped the land with sugar, flour, and magic, Crimson Castle now stands silent.",
		"Once a beacon of creation, its grand halls are now empty, its ovens cold, and its once-welcoming doors sealed shut by unseen forces.",
		"The people whisper of its former glory, and of the Crimson Confectioner, the man who built an empire of sweetness with nothing but a whisk and a dream. Yet they also whisper of his sudden, inexplicable disappearance.",
		"Some say the magic of sugar and spice became too much, twisting his mind until he could no longer distinguish reality from his own creations. Others believe he still lingers within the castle\226\128\153s walls, lost in the echoes of his past, trapped by the very dream he brought to life.",
		"Long before he was the Crimson Confectioner, he was merely a warrior without a cause. Born into a lineage of fighters, trained to wield a sword rather than a spoon, he spent his youth in battlefields and barracks, honing skills that were meant to shape him into a great warlord.",
		"While others found purpose in combat, his heart beat for something else\226\128\148the tug of magic, the pull of something softer, something sweeter. At night, while his fellow warriors polished blades, he would sneak away, sketching recipes instead of battle strategies, dreaming of flavors instead of conquest.",
		"The Crimson Confectioner left behind his former life and ventured into a land of nothingness. A barren world. A blank slate. And for the first time in his life, he dreamed freely.",
		"Crimson Castle was not just the Crimson Confectioner\'s home, but his sanctuary, his masterpiece, his heart.",
		"Crimson Castle was a haven for dreamers, for wanderers who, like him, had been cast aside for daring to imagine something greater. He welcomed bakers, alchemists, candy-makers, and farmers of rare, enchanted ingredients."
	},
	WolperHole = { "Wolpers don\226\128\153t just dig holes\226\128\148they sculpt future havens with every joyful stomp of their hooves.", "Wolper-dug caverns sparkle with blooming crystal flowers that only sprout where hooves have danced.", "The longer a Wolper hole is left undisturbed, the more it becomes a glittering cradle of wild magic.", "Critters of all kinds wait patiently for the Wolpers to finish digging, eager to move into their cozy underground homes.Every tunnel dug is a promise\226\128\148of shelter from storms, of warmth, of safety beneath the earth.", "Wolpers return to old tunnels like cherished memories, adding new paths as their stories grow." },
	WolperLore = { "Wolpers bounce through life with twitching ears, fluffy tails, and hearts full of wonder. Some say Wolpers carry springtime magic in their bones\226\128\148where they hop, life blossoms.", "Young Wolpers often challenge each other to hop contests, bouncing joyfully from hill to hill.Their powerful legs can launch them over trees, but it\226\128\153s not the height\226\128\148it\226\128\153s the thrill\226\128\148that keeps them hopping.", "Wolpers adore crafting trinkets from moss, crystals, and petals\226\128\148every den a glowing gallery.", "Wolpers make the best farmhands, plucking weeds, fluffing soil, and helping crops bloom with just a hop and a hum. They tend gardens like sacred art, though they do nibble the juiciest strawberries when no one\226\128\153s watching.", "Catch a Wolper daydreaming and they\226\128\153re likely planning their next hop, hole, or harvest." },
	WolperBarn = { "Wolpers are Aetheron\226\128\153s most devoted farmers, rising with the sun and working the fields with cheerful purpose.", "Many villages in Aetheron owes its harvest to a Wolper hoof and a hop-filled heart. Wolpers treat farming not as labor, but as a sacred rhythm\226\128\148plant, tend, harvest, share.", "Aetheron\226\128\153s granaries are filled thanks to Wolper villages that work year-round, rain or shine, hoof-deep in earth.", "Wolper farming communes are the heartbeat of every region\226\128\153s food chain\226\128\148they plant for themselves, their neighbors, and the future.", "Wolper young are taught from birth to share every harvest, carve planting runes, and leave seeds behind wherever they roam. Travelers passing by their barns are greeted with baskets of foraged fruits and smiling flower crowns." },
	WolperFarmland = { "Wolpers enchanted their tools with bloomcharms and growth-whistles, making the soil hum with health. They plant with their hooves, kick up soil with precision, and whistle tunes that make crops sway happily in the breeze.", "It\226\128\153s said that where a Wolper hops, weeds retreat, and roots stretch just a little deeper. They use moonlight to guide nighttime harvests, trusting lunar phases like old friends.", "Even during frostfall or scorching drought, Wolper fields remain vibrant, glowing faintly under the care of shared magic.", "Rain or shine, the crops know they are loved, and in return, they grow sweeter, taller, and richer than any wild field.", "Wolper fields thrive because no hoof tends alone\226\128\148there\226\128\153s always a burrowmate, a cousin, or a neighbor nearby, laughing through the soil." },
	Circus = { "Only the most gifted carousel horses earn a spot. Each bears a carved emblem on its breastplate symbolizing its act\226\128\148meteor lassoing, ribbon-hoof acrobatics, or torch-whirl choreography.", "Once per season the troupe reunites at the carnival to perform an all-skills spectacle, combining flame, water, and crystal light into an aurora that crowns the big-top for a single breathtaking hour.", "Between shows the troupe wheels its enchanted wagons across continents. Their copper wheels leave faint, glittery grooves that mark a safe path for wandering foals." },
	Carnival = { "The carousel horses take shifts running ring-toss, apple-dart booths, and mirror mazes. Their magic lets them \226\128\156bend\226\128\157 luck just enough so foals and first-timers almost always win something glittery." },
	FoodTents = { "Confectioners cultivate sugarcane that sprouts like flowers overnight. Ground to stardust sugar, it keeps treats cool and safe for equine bellies while adding a subtle, rejuvenating fizz.", "Food here hums with joy and fizz.", "Smells like dreams and taste even better." },
	Arches = { "Worn stone, still standing proud", "Whispers pass through the stone.", "Old arches watching the fun unfold." },
	BeachCrystal = { "At low tide, prismatic crystals grow like coral. Carnival engineers harvest only the fallen shards, which can hold sunlight for weeks and are slotted into lanterns that light the midway.", "When waves strike crystal clusters, they ring like distant chimes. Showrunners time firework finales to this natural music so sky-bursts and sea-song blend into one symphony.", "Horses dash along the wet sand at dawn, their reflections splitting through crystal puddles into kaleidoscopic echoes\226\128\148said to boost a steed\226\128\153s speed for the rest of the day." },
	Castle = { "Every stone of the royal castle hums with old magic, sealed within its halls by the will of ancient hooves.", "The towers never cast the same shadow twice, as if the castle dreams while it stands." },
	RoyalMaze = { "Those who enter the royal maze say it shifts ever so slightly, guiding only the sure of heart to its center.", "Flowers only bloom at dead ends, as if the maze rewards those who get lost." },
	Gazebo = { "Petals drift endlessly around the gazebo.", "The breeze inside the gazebo always smells like the first day of spring, no matter the season." },
	CrystalHorseStatues = { "The statues catch the sun just right at dawn, some say that\226\128\153s when they remember who they once were.", "Crystals hum softly when the moon is full, echoing forgotten hoofbeats frozen in time." },
	AlienPlants = { "These plants feed not on sunlight, but on minerals and faint stellar radiation absorbed by the meteoroid\226\128\153s stone.", "Vines drip glowing sap that nourishes Equenari and enhances their adaptive biology.", "Thick, rubbery stalks protect hidden pockets of vapor\226\128\148Equenari drink from these to survive long void journeys.", "The flora is mutagenic, seeding constant variation in Equenari physiology." },
	Meteorite = { "Equenari meteors are hollow worlds, filled with caverns of crystal and alien growths.", "When meteors drift near each other, they exchange spores, pollen, and even living matter, keeping their ecosystems diverse.", "The meteors orbit Aetheron in vast pods, each carrying unique strains of plants and Equenari.", "Inside, flora and fauna exist in balance, ensuring Equenari thrive until a crash disperses them." },
	EquenariStalls = { "Equenari are dual-natured: grazing on alien flora, yet equally capable of predation.", "They do not reproduce in natural ways; instead, they emerge from plant-grown cocoons deep inside meteoroids.", "To Aetheron\226\128\153s people, Equenari are viewed as a living invasion\226\128\148an unstoppable fusion of beast and ecosystem." },
	SharpAlienVines = { "When meteors crash, spores spread rapidly, smothering native ecosystems.", "Some invasive plants release pollen that clouds thought and weakens magical defenses.", "Others grow parasitic roots that drain vitality from Aetheron\226\128\153s ancient groves." }
}